import { useState } from "react";
import { T } from "../tokens.js";
import { Label, Rule } from "./ui.jsx";

// ─── Claude call — returns structured comparison JSON ─────────────────────────
async function fetchExample(stroke, itemName, feedback) {
  const prompt = `You are an expert swimming coach. A club swimmer has been flagged for this technique issue:

  Stroke: ${stroke}
  Item: ${itemName}
  Observed problem: ${feedback}

  Return ONLY valid JSON in this exact structure — no markdown, no preamble:
  {
    "incorrectTitle": "<short label for the bad position, e.g. 'Head too high'>",
      "incorrectDesc": "<1 sentence describing the exact mistake and its effect>",
        "correctTitle": "<short label for the correct position, e.g. 'Head neutral'>",
          "correctDesc": "<1 sentence describing what correct looks like and why it helps>",
            "coachingCue": "<memorable 1-phrase cue a coach would say poolside, e.g. 'One goggle in the water'>",
              "svgIncorrect": "<inline SVG string, viewBox='0 0 120 80', simple side-view stick figure showing the WRONG position. Use stroke='#E7002A' for the body, a circle for the head, lines for body/arms/legs. No text inside SVG.>",
                "svgCorrect": "<inline SVG string, viewBox='0 0 120 80', same style showing the CORRECT position. Use stroke='#007A5E'.>"
                }

                SVG guidelines:
                - viewBox="0 0 120 80", width/height not set (will be controlled by CSS)
                - fill="none", strokeWidth="2.5", strokeLinecap="round"
                - Draw a simple horizontal swimmer: circle for head (~r=7), line for torso, lines for arms and legs
                - Show the key difference clearly — e.g. for head position, draw head angle differently
                - Keep it minimal — 5 to 8 path/line/circle elements max
                - No labels or text nodes inside the SVG`;

                  const res = await fetch("/api/messages", {
                      method: "POST",
                          headers: { "Content-Type": "application/json" },
                              body: JSON.stringify({
                                    model: "claude-sonnet-4-20250514",
                                          max_tokens: 800,
                                                messages: [{ role: "user", content: prompt }],
                                                    }),
                                                      });
                                                        const data = await res.json();
                                                          const text = data.content?.map((b) => b.text || "").join("") || "";
                                                            return JSON.parse(text.replace(/```json|```/g, "").trim());
                                                            }

                                                            // ─── Modal overlay ────────────────────────────────────────────────────────────
                                                            export function TechniqueExample({ item, stroke, accent, onClose }) {
                                                              const [example, setExample] = useState(null);
                                                                const [loading, setLoading] = useState(false);
                                                                  const [error, setError]     = useState(null);

                                                                    const load = async () => {
                                                                        setLoading(true);
                                                                            setError(null);
                                                                                try {
                                                                                      const data = await fetchExample(stroke, item.name, item.feedback);
                                                                                            setExample(data);
                                                                                                } catch {
                                                                                                      setError("Could not load example — please try again.");
                                                                                                          }
                                                                                                              setLoading(false);
                                                                                                                };

                                                                                                                  // Auto-load on mount
                                                                                                                    useState(() => { load(); }, []);
                                                                                                                      // Use useEffect pattern via inline call on first render
                                                                                                                        if (!loading && !example && !error) load();

                                                                                                                          return (
                                                                                                                              // ── Overlay ──────────────────────────────────────────────────────────────
                                                                                                                                  <div
                                                                                                                                        onClick={onClose}
                                                                                                                                              style={{
                                                                                                                                                      position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)",
                                                                                                                                                              zIndex: 200, display: "flex", alignItems: "flex-end",
                                                                                                                                                                      justifyContent: "center",
                                                                                                                                                                            }}>

                                                                                                                                                                                  {/* Sheet — stops click propagation so tapping inside doesn't close */}
                                                                                                                                                                                        <div
                                                                                                                                                                                                onClick={(e) => e.stopPropagation()}
                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                  background: T.white, width: "100%", maxWidth: 480,
                                                                                                                                                                                                                            borderRadius: "16px 16px 0 0", padding: "0 0 40px",
                                                                                                                                                                                                                                      maxHeight: "88vh", overflowY: "auto",
                                                                                                                                                                                                                                              }}>

                                                                                                                                                                                                                                                      {/* Handle + header */}
                                                                                                                                                                                                                                                              <div style={{ padding: "16px 24px 0", textAlign: "center" }}>
                                                                                                                                                                                                                                                                        <div style={{ width: 36, height: 3, background: T.rule, borderRadius: 2, margin: "0 auto 20px" }} />
                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                        <div style={{ padding: "0 24px 20px" }}>
                                                                                                                                                                                                                                                                                                  <Label style={{ color: accent, marginBottom: 4 }}>{stroke} · Technique Example</Label>
                                                                                                                                                                                                                                                                                                            <div style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 18, fontWeight: 300, letterSpacing: "-0.02em", color: T.black, lineHeight: 1.3 }}>
                                                                                                                                                                                                                                                                                                                        {item.name}
                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                  <Rule />

                                                                                                                                                                                                                                                                                                                                                          {/* States */}
                                                                                                                                                                                                                                                                                                                                                                  {loading && (
                                                                                                                                                                                                                                                                                                                                                                            <div style={{ padding: "48px 24px", textAlign: "center" }}>
                                                                                                                                                                                                                                                                                                                                                                                        <Label style={{ display: "block", marginBottom: 8 }}>Generating example…</Label>
                                                                                                                                                                                                                                                                                                                                                                                                    <div style={{ width: 32, height: 1, background: T.rule, margin: "0 auto" }} />
                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                      )}

                                                                                                                                                                                                                                                                                                                                                                                                                              {error && (
                                                                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ margin: "20px 24px", padding: "12px 16px", background: "#FFF0F0", borderLeft: `3px solid ${T.red}` }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 12, color: T.red }}>{error}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button onClick={load} style={{ display: "block", marginTop: 8, background: "none", border: "none", color: accent, fontSize: 12, cursor: "pointer", padding: 0 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Try again →
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {example && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div style={{ padding: "24px 24px 0" }}>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* Side-by-side diagrams */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 24 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Incorrect */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ border: `1px solid ${T.rule}`, borderTop: `3px solid ${T.red}` }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ padding: "10px 12px 6px", background: "#FFF0F0" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Label style={{ color: T.red, marginBottom: 2 }}>✗ Incorrect</Label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 11, fontWeight: 600, color: T.dark }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {example.incorrectTitle}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{ padding: "12px", display: "flex", justifyContent: "center", background: T.offWhite }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                dangerouslySetInnerHTML={{ __html: example.svgIncorrect?.replace(/<svg/, '<svg width="100%" style="max-height:80px"') }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ padding: "10px 12px" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 11, color: T.mid, lineHeight: 1.5, margin: 0 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {example.incorrectDesc}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Correct */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ border: `1px solid ${T.rule}`, borderTop: `3px solid #007A5E` }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ padding: "10px 12px 6px", background: "#EBF7F4" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Label style={{ color: "#007A5E", marginBottom: 2 }}>✓ Correct</Label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 11, fontWeight: 600, color: T.dark }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {example.correctTitle}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{ padding: "12px", display: "flex", justifyContent: "center", background: T.offWhite }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                dangerouslySetInnerHTML={{ __html: example.svgCorrect?.replace(/<svg/, '<svg width="100%" style="max-height:80px"') }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ padding: "10px 12px" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 11, color: T.mid, lineHeight: 1.5, margin: 0 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {example.correctDesc}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* Coaching cue */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ padding: "14px 16px", background: T.offWhite, borderLeft: `3px solid ${accent}`, marginBottom: 24 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Label style={{ marginBottom: 6, color: accent }}>Poolside coaching cue</Label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 16, fontWeight: 300, color: T.black, letterSpacing: "-0.01em", fontStyle: "italic" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      "{example.coachingCue}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {/* Drill reminder */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {item.drill && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ marginBottom: 24 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <Label style={{ marginBottom: 6 }}>Recommended drill</Label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif", fontSize: 13, color: T.dark, lineHeight: 1.5 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {item.drill}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {/* Close button */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div style={{ padding: "0 24px" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <Rule style={{ marginBottom: 16 }} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onClick={onClose}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              width: "100%", padding: "13px", background: "none",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            border: `1px solid ${T.rule}`, cursor: "pointer",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          fontFamily: "'Helvetica Neue',Helvetica,Arial,sans-serif",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fontSize: 12, letterSpacing: "0.08em", textTransform: "uppercase", color: T.mid,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Close
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              